1	// Image-to-3D house model via fal-ai/trellis-2.
2	// Replaces the procedural BuildingRenderer for the new aerial-driven flow:
3	// triggers /api/trellis on mount, shows an animated wireframe skeleton until
4	// the GLB is back, then loads & rescales it to fit the existing footprint
5	// (so the panels mounted by <Panels/> still align).
6	
7	'use client';
8	
9	import { Suspense, useEffect, useMemo, useRef, useState } from 'react';
10	import { useFrame, useLoader } from '@react-three/fiber';
11	import { Edges, Html, Billboard } from '@react-three/drei';
12	import { Box3, Group, Mesh, Shape, TextureLoader, Vector3 } from 'three';
13	import { GLTFLoader } from 'three/examples/jsm/loaders/GLTFLoader.js';
14	import { useStore } from '@/lib/store';
15	import { useHouseGeometry } from './HouseGeometry';
16	import { HOUSE_COORDS } from './vision/houseLatLng';
17	import type { HouseId } from '@/lib/types';
18	
19	type Status =
20	  | { kind: 'idle' }
21	  | { kind: 'generating'; sinceMs: number }
22	  | { kind: 'ready'; glbUrl: string }
23	  | { kind: 'error'; message: string };
24	
25	// Aesthetic skeleton dimensions — keep the placeholder tall and house-shaped
26	// regardless of the eventual footprint (which can be wide/squat for some demo
27	// houses and would render as a flat slab). The GLB replaces this once ready,
28	// at which point its real footprint determines the size.
29	const SKELETON_WIDTH = 4;
30	const SKELETON_DEPTH = 4.4;
31	const SKELETON_WALL = 3.5;
32	
33	export function TrellisModel({ houseId }: { houseId: HouseId | 'custom' }) {
34	  const coords = useResolvedCoords(houseId);
35	  const { width, depth, wallHeight } = useHouseGeometry();
36	  const setTrellisStatus = useStore((s) => s.setTrellisStatus);
37	  const [status, setStatus] = useState<Status>({ kind: 'idle' });
38	
39	  // Trigger /api/trellis whenever lat/lng changes. The route is sync (~30-60s)
40	  // so we just await the JSON; the skeleton animates while we wait. We also
41	  // mirror the status into the Zustand store so the design page overlays
42	  // (KPISidebar, ControlPanel, …) and the Orchestrator can gate on it.
43	  useEffect(() => {
44	    if (!coords) return;
45	    let cancelled = false;
46	    const startedAt = Date.now();
47	    setStatus({ kind: 'generating', sinceMs: startedAt });
48	    setTrellisStatus('generating');
49	
50	    (async () => {
51	      try {
52	        const res = await fetch('/api/trellis', {
53	          method: 'POST',
54	          headers: { 'content-type': 'application/json' },
55	          body: JSON.stringify({ lat: coords.lat, lng: coords.lng }),
56	        });
57	        const json = (await res.json()) as { ok: boolean; glbUrl?: string; error?: string };
58	        if (cancelled) return;
59	        if (!json.ok || !json.glbUrl) {
60	          setStatus({ kind: 'error', message: json.error ?? 'Generation failed' });
61	          setTrellisStatus('error');
62	          return;
63	        }
64	        setStatus({ kind: 'ready', glbUrl: json.glbUrl });
65	        setTrellisStatus('ready');
66	      } catch (err) {
67	        if (cancelled) return;
68	        setStatus({
69	          kind: 'error',
70	          message: err instanceof Error ? err.message : 'network error',
71	        });
72	        setTrellisStatus('error');
73	      }
74	    })();
75	
76	    return () => {
77	      cancelled = true;
78	    };
79	  }, [coords?.lat, coords?.lng, houseId, setTrellisStatus]);
80	
81	  // Screenshot URL (the same oblique screenshot fal will analyze) — fetched
82	  // in parallel by the browser as a TextureLoader so we can show it as a
83	  // backdrop while waiting. Browser cache means /api/aerial only runs once
84	  // even though /api/trellis also pulls it server-side.
85	  const screenshotUrl = coords
86	    ? `/api/aerial?lat=${coords.lat}&lng=${coords.lng}&zoom=20&tilted=1`
87	    : null;
88	
89	  return (
90	    <group>
91	      <Ground />
92	      {screenshotUrl && status.kind !== 'idle' && (
93	        <Suspense fallback={null}>
94	          <ScreenshotBillboard
95	            url={screenshotUrl}
96	            // Fade out once GLB is ready (we'll cross-fade through the morph).
97	            isReady={status.kind === 'ready'}
98	          />
99	        </Suspense>
100	      )}
101	      <MorphingBuilding
102	        status={status}
103	        glbWidth={width}
104	        glbDepth={depth}
105	        glbHeight={wallHeight}
106	      />
107	    </group>
108	  );
109	}
110	
111	// Wrap skeleton + GLB together so we can cross-fade between them over a
112	// ~1.5s morph window when status transitions from generating → ready.
113	function MorphingBuilding({
114	  status,
115	  glbWidth,
116	  glbDepth,
117	  glbHeight,
118	}: {
119	  status: Status;
120	  glbWidth: number;
121	  glbDepth: number;
122	  glbHeight: number;
123	}) {
124	  const transitionStartedRef = useRef<number | null>(null);
125	  const [transitionT, setTransitionT] = useState(0); // 0..1 over MORPH_MS
126	  const MORPH_MS = 1500;
127	
128	  useEffect(() => {
129	    if (status.kind === 'ready' && transitionStartedRef.current === null) {
130	      transitionStartedRef.current = performance.now();
131	    }
132	  }, [status.kind]);
133	
134	  useFrame(() => {
135	    if (transitionStartedRef.current === null) return;
136	    const elapsed = performance.now() - transitionStartedRef.current;
137	    const t = Math.min(1, elapsed / MORPH_MS);
138	    if (t !== transitionT) setTransitionT(t);
139	  });
140	
141	  // Easing: smoothstep. Skeleton fade-out is 1-ease(t); GLB fade-in is ease(t).
142	  const ease = transitionT * transitionT * (3 - 2 * transitionT);
143	  const skeletonOpacity = status.kind === 'ready' ? 1 - ease : 1;
144	  const glbOpacity = status.kind === 'ready' ? ease : 0;
145	  const skeletonScale = status.kind === 'ready' ? 1 + ease * 0.4 : 1;
146	  const glbScale = status.kind === 'ready' ? 0.6 + ease * 0.4 : 0.6;
147	
148	  return (
149	    <>
150	      {/* Skeleton: visible until morph completes, then unmounted. */}
151	      {skeletonOpacity > 0.02 && (
152	        <group scale={skeletonScale}>
153	          <Skeleton
154	            width={SKELETON_WIDTH}
155	            depth={SKELETON_DEPTH}
156	            height={SKELETON_WALL}
157	            opacityMul={skeletonOpacity}
158	            message={
159	              status.kind === 'generating'
160	                ? 'Generating 3D model'
161	                : status.kind === 'error'
162	                ? `Failed: ${status.message}`
163	                : status.kind === 'ready'
164	                ? undefined
165	                : 'Preparing'
166	            }
167	            tone={status.kind === 'error' ? 'error' : 'busy'}
168	          />
169	        </group>
170	      )}
171	
172	      {/* GLB: fades in during the morph window, full opacity afterwards. */}
173	      {status.kind === 'ready' && (
174	        <Suspense fallback={null}>
175	          <group scale={glbScale}>
176	            <LoadedGlb
177	              url={status.glbUrl}
178	              width={glbWidth}
179	              depth={glbDepth}
180	              height={glbHeight}
181	              opacity={glbOpacity}
182	            />
183	          </group>
184	        </Suspense>
185	      )}
186	    </>
187	  );
188	}
189	
190	// Screenshot of the oblique aerial view (Cesium + 3D Tiles) shown as a
191	// billboard always facing the camera. Fades in once the texture loads,
192	// fades out when the GLB is ready so the eye is drawn back to the model.
193	function ScreenshotBillboard({ url, isReady }: { url: string; isReady: boolean }) {
194	  const texture = useLoader(TextureLoader, url);
195	  const meshRef = useRef<Mesh>(null);
196	  const fadeStartRef = useRef<number>(performance.now());
197	
198	  useFrame(() => {
199	    const mat = meshRef.current?.material as { opacity?: number } | undefined;
200	    if (!mat) return;
201	    const elapsed = performance.now() - fadeStartRef.current;
202	    if (isReady) {
203	      // Fade out over 800ms once GLB is ready.
204	      mat.opacity = Math.max(0, 0.55 * (1 - elapsed / 800));
205	    } else {
206	      // Fade in over 600ms after texture loaded.
207	      mat.opacity = Math.min(0.55, (elapsed / 600) * 0.55);
208	    }
209	  });
210	
211	  // Reset fade timer when isReady flips.
212	  useEffect(() => {
213	    fadeStartRef.current = performance.now();
214	  }, [isReady]);
215	
216	  // Aspect ratio from the texture (most Cesium screenshots are square ~1280x1280).
217	  const aspect = (texture.image?.width ?? 1) / (texture.image?.height ?? 1);
218	  const W = 9;
219	  const H = W / aspect;
220	
221	  return (
222	    <Billboard position={[0, 5, -7]} follow lockX={false} lockY={false} lockZ={false}>
223	      <mesh ref={meshRef}>
224	        <planeGeometry args={[W, H]} />
225	        <meshBasicMaterial
226	          map={texture}
227	          transparent
228	          opacity={0}
229	          depthWrite={false}
230	          toneMapped={false}
231	        />
232	      </mesh>
233	    </Billboard>
234	  );
235	}
236	
237	// ─── Skeleton (in-canvas) ───────────────────────────────────────────────────
238	// Wireframe box pulsing in opacity so the user always sees "something is
239	// happening" — even before /api/trellis returns. A small <Html> badge floats
240	// above with the current status text.
241	
242	function Skeleton({
243	  width,
244	  depth,
245	  height,
246	  message,
247	  tone = 'busy',
248	  opacityMul = 1,
249	}: {
250	  width: number;
251	  depth: number;
252	  height: number;
253	  message?: string;
254	  tone?: 'busy' | 'error';
255	  /** Multiplies all rendered material opacities (used during morph fade-out). */
256	  opacityMul?: number;
257	}) {
258	  const houseRef = useRef<Group>(null);
259	  const wallsRef = useRef<Mesh>(null);
260	  const roofRef = useRef<Mesh>(null);
261	  const scanRef = useRef<Mesh>(null);
262	  const haloRef = useRef<Mesh>(null);
263	  const startedAt = useRef<number>(performance.now());
264	  const [elapsedSec, setElapsedSec] = useState(0);
265	
266	  useEffect(() => {
267	    if (tone !== 'busy') return;
268	    const id = setInterval(() => {
269	      setElapsedSec(Math.floor((performance.now() - startedAt.current) / 1000));
270	    }, 1000);
271	    return () => clearInterval(id);
272	  }, [tone]);
273	
274	  // Tall storybook roof so the silhouette reads as "house" not "shed".
275	  const roofHeight = height * 0.75;
276	  const totalH = height + roofHeight;
277	  const planSize = Math.max(width, depth);
278	
279	  // Triangular gable cross-section, extruded along the depth axis to make a
280	  // proper house roof (not a 4-sided pyramid).
281	  const roofShape = useMemo(() => {
282	    const s = new Shape();
283	    s.moveTo(-width / 2, 0);
284	    s.lineTo(width / 2, 0);
285	    s.lineTo(0, roofHeight);
286	    s.lineTo(-width / 2, 0);
287	    return s;
288	  }, [width, roofHeight]);
289	
290	  useFrame(({ clock }) => {
291	    const t = clock.elapsedTime;
292	    // Continuous slow yaw — looks like the house is being inspected from all
293	    // sides. ~1 turn every 12 seconds.
294	    if (houseRef.current) {
295	      houseRef.current.rotation.y = t * (Math.PI * 2) / 12;
296	    }
297	    // Walls + roof: gentle opacity pulse on the wireframe edges. Scaled by
298	    // opacityMul so the parent can fade us out during the morph.
299	    const pulse = (0.55 + Math.sin(t * 2.5) * 0.25) * opacityMul;
300	    const wallsMat = wallsRef.current?.material as { opacity?: number } | undefined;
301	    if (wallsMat && 'opacity' in wallsMat) wallsMat.opacity = pulse;
302	    const roofMat = roofRef.current?.material as { opacity?: number } | undefined;
303	    if (roofMat && 'opacity' in roofMat) roofMat.opacity = pulse;
304	
305	    // Scan plane sweeping bottom→top→bottom over ~3s.
306	    if (scanRef.current) {
307	      const phase = (Math.sin(t * 1.0) + 1) * 0.5;
308	      scanRef.current.position.y = phase * totalH;
309	      const mat = scanRef.current.material as { opacity?: number } | undefined;
310	      if (mat && 'opacity' in mat) mat.opacity = (0.6 - Math.abs(phase - 0.5) * 0.5) * opacityMul;
311	    }
312	    // Halo at the ground — slow expand/contract.
313	    if (haloRef.current) {
314	      const breath = 1 + (Math.sin(t * 1.6) + 1) * 0.18;
315	      haloRef.current.scale.set(breath, breath, breath);
316	      const mat = haloRef.current.material as { opacity?: number } | undefined;
317	      if (mat && 'opacity' in mat)
318	        mat.opacity = (0.32 - (Math.sin(t * 1.6) + 1) * 0.1) * opacityMul;
319	    }
320	  });
321	
322	  const color = tone === 'error' ? '#dc2626' : '#3b82f6';
323	  const glow = tone === 'error' ? '#fca5a5' : '#60a5fa';
324	
325	  return (
326	    <group>
327	      {/* ─── Rotating house skeleton (walls + gable roof) ────────────── */}
328	      <group ref={houseRef}>
329	        {/* Walls — wireframe box. Faint solid fill so the silhouette reads. */}
330	        <mesh ref={wallsRef} position={[0, height / 2, 0]}>
331	          <boxGeometry args={[width, height, depth]} />
332	          <meshBasicMaterial
333	            color={color}
334	            transparent
335	            opacity={0.08}
336	            depthWrite={false}
337	            wireframe={false}
338	          />
339	          <Edges color={color} threshold={1} lineWidth={2} />
340	        </mesh>
341	
342	        {/* Gable roof — triangular prism extruded from a 2D triangle shape. */}
343	        <mesh ref={roofRef} position={[0, height, -depth / 2]}>
344	          <extrudeGeometry args={[roofShape, { depth, bevelEnabled: false }]} />
345	          <meshBasicMaterial
346	            color={color}
347	            transparent
348	            opacity={0.08}
349	            depthWrite={false}
350	          />
351	          <Edges color={color} threshold={1} lineWidth={2} />
352	        </mesh>
353	      </group>
354	
355	      {/* ─── Scan plane traveling vertically (NOT inside the rotating group
356	          so the scan direction stays world-up, not house-up) ─────────── */}
357	      <mesh ref={scanRef} position={[0, 0, 0]} rotation={[-Math.PI / 2, 0, 0]}>
358	        <planeGeometry args={[planSize * 1.2, planSize * 1.2]} />
359	        <meshBasicMaterial color={glow} transparent opacity={0.5} depthWrite={false} toneMapped={false} />
360	      </mesh>
361	
362	      {/* ─── Ground halo ─────────────────────────────────────────────── */}
363	      <mesh ref={haloRef} position={[0, 0.01, 0]} rotation={[-Math.PI / 2, 0, 0]}>
364	        <ringGeometry args={[planSize * 0.55, planSize * 0.72, 64]} />
365	        <meshBasicMaterial color={glow} transparent opacity={0.25} depthWrite={false} toneMapped={false} />
366	      </mesh>
367	
368	      {/* ─── Floating badge — fixed pixel size, sits well above model ── */}
369	      {message && (
370	        <Html
371	          position={[0, totalH * 1.7, 0]}
372	          center
373	          style={{ pointerEvents: 'none' }}
374	          zIndexRange={[16777271, 16777271]}
375	        >
376	          <div className={tone === 'error' ? 'tm-card tm-card-error' : 'tm-card tm-card-busy'}>
377	            <div className="tm-card-bg" />
378	            <div className="tm-card-inner">
379	              <div className="tm-orb">
380	                <span className="tm-orb-core" />
381	                <span className="tm-orb-ring tm-orb-ring-1" />
382	                <span className="tm-orb-ring tm-orb-ring-2" />
383	              </div>
384	              <div className="tm-text">
385	                <div className="tm-title">
386	                  <span className="tm-title-text">{message}</span>
387	                  {tone === 'busy' && <span className="tm-ellipsis" />}
388	                </div>
389	                {tone === 'busy' && (
390	                  <div className="tm-sub">
391	                    <span className="tm-bars">
392	                      <span /><span /><span /><span /><span />
393	                    </span>
394	                    <span className="tm-elapsed">
395	                      {elapsedSec}s elapsed · usually ~45s
396	                    </span>
397	                  </div>
398	                )}
399	              </div>
400	            </div>
401	          </div>
402	          <style>{`
403	            .tm-card {
404	              position: relative;
405	              padding: 22px 34px;
406	              border-radius: 22px;
407	              font: 600 22px/1.2 system-ui, -apple-system, 'Segoe UI', sans-serif;
408	              white-space: nowrap;
409	              backdrop-filter: blur(18px) saturate(150%);
410	              -webkit-backdrop-filter: blur(18px) saturate(150%);
411	              overflow: hidden;
412	              box-shadow:
413	                0 1px 0 rgba(255,255,255,0.7) inset,
414	                0 20px 50px rgba(15,23,42,0.22),
415	                0 4px 14px rgba(15,23,42,0.12);
416	              transform: translateZ(0);
417	            }
418	            .tm-card-busy {
419	              color: #0c1f5a;
420	              background: linear-gradient(135deg, rgba(255,255,255,0.92) 0%, rgba(241,245,255,0.92) 100%);
421	              border: 1px solid rgba(59,130,246,0.35);
422	            }
423	            .tm-card-error {
424	              color: #7f1d1d;
425	              background: linear-gradient(135deg, rgba(255,255,255,0.95) 0%, rgba(254,242,242,0.95) 100%);
426	              border: 1px solid rgba(220,38,38,0.45);
427	            }
428	            /* Animated shimmer streaking diagonally across the card */
429	            .tm-card-bg {
430	              position: absolute;
431	              inset: 0;
432	              pointer-events: none;
433	              background: linear-gradient(
434	                115deg,
435	                transparent 30%,
436	                rgba(96,165,250,0.22) 48%,
437	                rgba(96,165,250,0.08) 52%,
438	                transparent 70%
439	              );
440	              background-size: 220% 100%;
441	              animation: tm-shimmer 2.6s linear infinite;
442	              mix-blend-mode: screen;
443	            }
444	            .tm-card-error .tm-card-bg {
445	              background: linear-gradient(
446	                115deg,
447	                transparent 30%,
448	                rgba(248,113,113,0.22) 48%,
449	                rgba(248,113,113,0.08) 52%,
450	                transparent 70%
451	              );
452	              background-size: 220% 100%;
453	              animation: tm-shimmer 2.6s linear infinite;
454	            }
455	            .tm-card-inner {
456	              position: relative;
457	              display: flex;
458	              align-items: center;
459	              gap: 18px;
460	            }
461	            .tm-text {
462	              display: flex;
463	              flex-direction: column;
464	              gap: 6px;
465	            }
466	            .tm-title {
467	              display: inline-flex;
468	              align-items: baseline;
469	              font-size: 28px;
470	              letter-spacing: -0.015em;
471	              font-weight: 700;
472	            }
473	            .tm-title-text {
474	              background: linear-gradient(90deg, currentColor 0%, currentColor 35%, #2563eb 50%, currentColor 65%, currentColor 100%);
475	              background-size: 200% 100%;
476	              -webkit-background-clip: text;
477	              background-clip: text;
478	              -webkit-text-fill-color: transparent;
479	              animation: tm-text-shine 2.6s linear infinite;
480	            }
481	            .tm-card-error .tm-title-text {
482	              -webkit-text-fill-color: currentColor;
483	              background: none;
484	              animation: none;
485	            }
486	            .tm-sub {
487	              display: inline-flex;
488	              align-items: center;
489	              gap: 12px;
490	              font-size: 14px;
491	              font-weight: 500;
492	              opacity: 0.7;
493	            }
494	            .tm-elapsed {
495	              font-variant-numeric: tabular-nums;
496	            }
497	            /* Equalizer-style bars (5 of them) */
498	            .tm-bars {
499	              display: inline-flex;
500	              align-items: flex-end;
501	              gap: 3px;
502	              height: 16px;
503	            }
504	            .tm-bars span {
505	              width: 4px;
506	              border-radius: 2px;
507	              background: currentColor;
508	              opacity: 0.85;
509	              animation: tm-bar 1.1s ease-in-out infinite;
510	            }
