1	// Real-time view of the 3 actual pipeline steps (CAPTURE → SIZE → MODEL).
2	// Driven entirely by the AgentStep[] in the store, which Orchestrator.tsx
3	// updates as each underlying promise resolves. No fake durations, no fake
4	// substeps — what you see is what's actually happening.
5	
6	'use client';
7	
8	import { motion } from 'framer-motion';
9	import { useEffect, useRef, useState } from 'react';
10	import { useStore } from '@/lib/store';
11	import type { AgentStep } from '@/lib/types';
12	
13	export function AgentTrace() {
14	  const steps = useStore((s) => s.agentSteps);
15	
16	  if (steps.length === 0) return null;
17	
18	  const totalDone = steps.filter((s) => s.status === 'done').length;
19	  const totalErr = steps.filter((s) => s.status === 'error').length;
20	  const progressPct = Math.round((totalDone / steps.length) * 100);
21	
22	  return (
23	    <motion.div
24	      initial={{ opacity: 0, x: -16 }}
25	      animate={{ opacity: 1, x: 0 }}
26	      transition={{ duration: 0.35 }}
27	      className="flex w-[380px] flex-col overflow-hidden rounded-3xl border border-zinc-200/70 bg-white shadow-[0_8px_28px_-12px_rgba(0,0,0,0.18)]"
28	    >
29	      {/* Header */}
30	      <div className="border-b border-zinc-100 px-5 py-4">
31	        <div className="mb-2.5 flex items-center justify-between">
32	          <div className="flex items-center gap-2">
33	            <span className="relative flex h-2 w-2">
34	              <span
35	                className={`absolute inline-flex h-full w-full rounded-full opacity-75 ${
36	                  totalErr > 0 ? 'bg-red-400' : 'animate-ping bg-blue-400'
37	                }`}
38	              />
39	              <span
40	                className={`relative inline-flex h-2 w-2 rounded-full ${
41	                  totalErr > 0 ? 'bg-red-500' : 'bg-blue-500'
42	                }`}
43	              />
44	            </span>
45	            <h2 className="text-[14px] font-bold tracking-tight text-zinc-900">
46	              AI pipeline
47	            </h2>
48	          </div>
49	          <span
50	            className={`font-mono text-[11px] font-bold ${
51	              totalErr > 0 ? 'text-red-600' : 'text-blue-600'
52	            }`}
53	          >
54	            {progressPct}%
55	          </span>
56	        </div>
57	        <div className="h-1 overflow-hidden rounded-full bg-zinc-100">
58	          <motion.div
59	            className={`h-full ${totalErr > 0 ? 'bg-red-500' : 'bg-blue-500'}`}
60	            initial={{ width: '0%' }}
61	            animate={{ width: `${progressPct}%` }}
62	            transition={{ duration: 0.4 }}
63	          />
64	        </div>
65	      </div>
66	
67	      {/* Steps */}
68	      <ol className="flex flex-col gap-2 px-4 py-4">
69	        {steps.map((step, i) => (
70	          <StepCard key={step.id} step={step} index={i + 1} />
71	        ))}
72	      </ol>
73	    </motion.div>
74	  );
75	}
76	
77	function StepCard({ step, index }: { step: AgentStep; index: number }) {
78	  const isDone = step.status === 'done';
79	  const isRunning = step.status === 'running';
80	  const isError = step.status === 'error';
81	  const isPending = step.status === 'pending';
82	
83	  const elapsed = useElapsedSeconds(isRunning);
84	
85	  // Border + background tone reflects state.
86	  const tone = isError
87	    ? 'border-red-200 bg-red-50/60'
88	    : isDone
89	    ? 'border-emerald-200 bg-emerald-50/40'
90	    : isRunning
91	    ? 'border-blue-200 bg-blue-50/60'
92	    : 'border-zinc-200 bg-zinc-50/40';
93	
94	  // Numbered status badge.
95	  const badge = isError ? (
96	    <BadgeIcon tone="error" content="!" />
97	  ) : isDone ? (
98	    <BadgeIcon tone="done" content="✓" />
99	  ) : isRunning ? (
100	    <BadgeSpinner />
101	  ) : (
102	    <BadgeIcon tone="pending" content={String(index)} />
103	  );
104	
105	  const labelClass = isPending
106	    ? 'text-zinc-400'
107	    : isError
108	    ? 'text-red-800'
109	    : isDone
110	    ? 'text-zinc-800'
111	    : 'text-zinc-900';
112	
113	  return (
114	    <motion.li
115	      initial={{ opacity: 0, y: 4 }}
116	      animate={{ opacity: 1, y: 0 }}
117	      transition={{ duration: 0.25 }}
118	      className={`flex items-start gap-3 rounded-2xl border p-3 transition ${tone}`}
119	    >
120	      <div className="flex-shrink-0 pt-0.5">{badge}</div>
121	      <div className="min-w-0 flex-1">
122	        <div className={`text-[13.5px] font-semibold leading-tight ${labelClass}`}>
123	          {step.label}
124	        </div>
125	        {step.sublabel && (
126	          <div className="mt-0.5 text-[11px] text-zinc-500">{step.sublabel}</div>
127	        )}
128	        {/* Result summary (e.g. "9.2 kWp · €11,400") shown when done. */}
129	        {isDone && step.resultLine && (
130	          <div className="mt-1.5 inline-block rounded-md bg-white px-2 py-0.5 font-mono text-[11px] font-semibold text-emerald-700 ring-1 ring-emerald-200">
131	            {step.resultLine}
132	          </div>
133	        )}
134	        {/* Live timer while running (only if the step is non-trivial). */}
135	        {isRunning && (
136	          <div className="mt-1 font-mono text-[10.5px] tabular-nums text-blue-600">
137	            {elapsed}s elapsed
138	          </div>
