    ? 'text-zinc-400'
    : isError
    ? 'text-red-800'
    : isDone
    ? 'text-zinc-800'
    : 'text-zinc-900';

  // Pulse ring keyframes fire on the running→done transition. The ring sits
  // above the card via box-shadow so it doesn't disturb layout.
  const cardAnimate = isDone
    ? {
        boxShadow: [
          '0 0 0 0 rgba(16,185,129,0)',
          '0 0 0 8px rgba(16,185,129,0.32)',
          '0 0 0 0 rgba(16,185,129,0)',
        ],
      }
    : {};

  return (
    <motion.li
      initial={{ opacity: 0, y: 4 }}
      animate={{ opacity: 1, y: 0, ...cardAnimate }}
      transition={{ duration: 0.25, boxShadow: { duration: 0.9, ease: 'easeOut' } }}
      className={`flex items-start gap-3 rounded-2xl border p-3 transition ${tone}`}
    >
      <div className="flex-shrink-0 pt-0.5">{badge}</div>
      <div className="min-w-0 flex-1">
        <div className={`text-[13.5px] font-semibold leading-tight ${labelClass}`}>
          {step.label}
        </div>
        {step.sublabel && (
          <div className="mt-0.5 text-[11px] text-zinc-500">{step.sublabel}</div>
        )}
        {/* Result summary (e.g. "9.2 kWp · €11,400") shown when done — springs in. */}
        {isDone && step.resultLine && (
          <motion.div
            initial={{ opacity: 0, y: -6, scale: 0.85 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            transition={{ type: 'spring', stiffness: 380, damping: 22, mass: 0.7 }}
            className="mt-1.5 inline-block rounded-md bg-white px-2 py-0.5 font-mono text-[11px] font-semibold text-emerald-700 ring-1 ring-emerald-200"
          >
            {step.resultLine}
          </motion.div>
        )}
        {/* Live timer while running (only if the step is non-trivial). */}
        {isRunning && (
          <div className="mt-1 font-mono text-[10.5px] tabular-nums text-blue-600">
            {elapsed}s elapsed
          </div>
        )}
        {isError && (
          <div className="mt-1 text-[11px] text-red-700">Step failed — see server log</div>
        )}
      </div>
      {/* Artifact thumbnail — flies in from the right with a slight rotation
          when the step lands, like it's being delivered to the slot. */}
      {isDone && step.artifactUrl && (
        <motion.img
          initial={{ opacity: 0, x: 80, scale: 0.4, rotate: -14 }}
          animate={{ opacity: 1, x: 0, scale: 1, rotate: 0 }}
          transition={{ type: 'spring', stiffness: 320, damping: 20, mass: 0.8 }}
          src={step.artifactUrl}
          alt={step.label}
          className="h-14 w-14 flex-shrink-0 rounded-lg object-cover ring-1 ring-zinc-200"
        />
      )}
    </motion.li>
  );
}

