export function AgentTrace() {
  const steps = useStore((s) => s.agentSteps);

  // Single-popup queue: ensures popups always appear in top-down step order,
  // even if `size` (parallel lane) finishes before `capture`/`clean`. When
  // the active popup closes after POPUP_HOLD_MS, the next eligible step's
  // popup opens. Popups already shown are remembered in the ref so we don't
  // replay them on every render.
  const shownRef = useRef<Set<string>>(new Set());
  const [activePopupId, setActivePopupId] = useState<string | null>(null);

  // Reset the "already shown" memory whenever the pipeline restarts (i.e. the
  // steps array becomes all-pending again — typically because the user
  // re-triggered the design flow with a new house).
  useEffect(() => {
    const anyDone = steps.some((s) => s.status === 'done');
    if (!anyDone && shownRef.current.size > 0) {
      shownRef.current.clear();
      setActivePopupId(null);
    }
  }, [steps]);

  // Drive the queue: whenever no popup is active, look for the first step (in
  // declaration order) that is done, has something to show, and hasn't been
  // popped yet. Open it for POPUP_HOLD_MS, then mark as shown.
  useEffect(() => {
    if (activePopupId) return;
    const next = steps.find(
      (s) =>
        s.status === 'done' &&
        !shownRef.current.has(s.id) &&
        (s.artifactUrl || s.resultLine),
    );
    if (!next) return;
    setActivePopupId(next.id);
    const t = setTimeout(() => {
      shownRef.current.add(next.id);
      setActivePopupId(null);
    }, POPUP_HOLD_MS);
    return () => clearTimeout(t);
  }, [steps, activePopupId]);

  if (steps.length === 0) return null;

  const totalDone = steps.filter((s) => s.status === 'done').length;
  const totalErr = steps.filter((s) => s.status === 'error').length;
  const progressPct = Math.round((totalDone / steps.length) * 100);

