function StepCard({ step, index }: { step: AgentStep; index: number }) {
  const isDone = step.status === 'done';
  const isRunning = step.status === 'running';
  const isError = step.status === 'error';
  const isPending = step.status === 'pending';

  const elapsed = useElapsedSeconds(isRunning);

  // Detect the running→done transition so we can show a centre-screen popup
  // that then morphs into the slot via shared layoutId.
  const prevStatus = useRef<AgentStep['status']>(step.status);
  const [popupOpen, setPopupOpen] = useState(false);
  useEffect(() => {
    if (prevStatus.current !== 'done' && step.status === 'done') {
      const hasArtifact = !!step.artifactUrl || !!step.resultLine;
      if (hasArtifact) {
        setPopupOpen(true);
        const t = setTimeout(() => setPopupOpen(false), POPUP_HOLD_MS);
        return () => clearTimeout(t);
      }
    }
    prevStatus.current = step.status;
  }, [step.status, step.artifactUrl, step.resultLine]);

