// Drive the queue: whenever no popup is active, look for the next step (in
// declaration order) that is done, has something to show, and hasn't been
// popped yet. Strict top-down — a later step's popup waits until every
// earlier step has either been shown or has nothing to show. This matters
// because `size` runs in parallel and often finishes before `capture`.
useEffect(() => {
  if (activePopupId) return;
  const next = steps.find((s, i) => {
    if (s.status !== 'done') return false;
    if (shownRef.current.has(s.id)) return false;
    if (!s.artifactUrl && !s.resultLine) return false;
    for (let j = 0; j < i; j++) {
      const earlier = steps[j];
      // Still in progress upstream → block.
      if (earlier.status !== 'done' && earlier.status !== 'error') return false;
      const earlierEligible = !!earlier.artifactUrl || !!earlier.resultLine;
      // Earlier step has a popup pending → block.
      if (earlierEligible && !shownRef.current.has(earlier.id)) return false;
    }
    return true;
  });
  if (!next) return;
  setActivePopupId(next.id);
  const t = setTimeout(() => {
    shownRef.current.add(next.id);
    setActivePopupId(null);
  }, POPUP_HOLD_MS);
  return () => clearTimeout(t);
}, [steps, activePopupId]);

