  houseId: HouseId | null;
  customAddress?: string;
  onReady: (p: CustomerProfile) => void;
  onGenerate: () => void;
  ready: boolean;
}

const FIELD_KEYS: (keyof CustomerProfile)[] = [
  'inhabitants',
  'annualConsumptionKwh',
  'houseSizeSqm',
  'heatingType',
  'hasEv',
];

